import akka.actor.{Actor, ActorLogging, ActorRef, ActorSystem, Props}
import akka.pattern.ask
import akka.util.Timeout

import scala.concurrent.duration._
import scala.util.{Failure, Success}

// Sealed trait prevents unauthorized message types
sealed trait AccountMessage

// Commands
final case class Deposit(amount: BigDecimal, transactionId: String) extends AccountMessage
final case class Withdraw(amount: BigDecimal, transactionId: String) extends AccountMessage
final case class GetBalance(requestId: String) extends AccountMessage

// Responses - sealed to prevent tampering
sealed trait AccountResponse
final case class TransactionSuccess(transactionId: String, newBalance: BigDecimal) extends AccountResponse
final case class TransactionFailure(transactionId: String, reason: String) extends AccountResponse
final case class BalanceResponse(requestId: String, balance: BigDecimal) extends AccountResponse

class AccountActor(accountId: String) extends Actor with ActorLogging {

  // Safe to use var inside an actor - Akka guarantees single-threaded message processing
  // This mutable state is NEVER exposed directly outside the actor
  private var balance: BigDecimal = BigDecimal(0)

  // Keep an audit log of recent transactions for accountability
  private var auditLog: Vector[String] = Vector.empty
  private val maxAuditLogSize = 10000

  override def receive: Receive = {
    case Deposit(amount, transactionId) =>
      handleDeposit(amount, transactionId, sender())

    case Withdraw(amount, transactionId) =>
      handleWithdraw(amount, transactionId, sender())

    case GetBalance(requestId) =>
      log.info(s"Balance inquiry for account $accountId, requestId=$requestId")
      sender() ! BalanceResponse(requestId, balance)
  }

  private def handleDeposit(amount: BigDecimal, transactionId: String, replyTo: ActorRef): Unit = {
    // Input validation - critical for financial systems
    if (amount <= 0) {
      log.warning(s"Rejected deposit with non-positive amount: $amount, txn=$transactionId, account=$accountId")
      replyTo ! TransactionFailure(transactionId, "Deposit amount must be positive")
      return
    }

    if (amount > BigDecimal("1000000000")) {
      log.warning(s"Rejected deposit exceeding maximum limit: $amount, txn=$transactionId, account=$accountId")
      replyTo ! TransactionFailure(transactionId, "Deposit amount exceeds maximum allowed limit")
      return
    }

    val previousBalance = balance
    balance = balance + amount

    // Overflow/sanity check
    if (balance < previousBalance) {
      balance = previousBalance
      log.error(s"Balance overflow detected for account $accountId, txn=$transactionId")
      replyTo ! TransactionFailure(transactionId, "Transaction would cause balance overflow")
      return
    }

    appendAuditLog(s"DEPOSIT txn=$transactionId amount=$amount previousBalance=$previousBalance newBalance=$balance")
    log.info(s"Deposit successful: account=$accountId, txn=$transactionId, amount=$amount, newBalance=$balance")
    replyTo ! TransactionSuccess(transactionId, balance)
  }

  private def handleWithdraw(amount: BigDecimal, transactionId: String, replyTo: ActorRef): Unit = {
    // Input validation
    if (amount <= 0) {
      log.warning(s"Rejected withdrawal with non-positive amount: $amount, txn=$transactionId, account=$accountId")
      replyTo ! TransactionFailure(transactionId, "Withdrawal amount must be positive")
      return
    }

    if (amount > balance) {
      log.warning(s"Insufficient funds: account=$accountId, txn=$transactionId, requested=$amount, available=$balance")
      replyTo ! TransactionFailure(transactionId, "Insufficient funds")
      return
    }

    val previousBalance = balance
    balance = balance - amount

    appendAuditLog(s"WITHDRAW txn=$transactionId amount=$amount previousBalance=$previousBalance newBalance=$balance")
    log.info(s"Withdrawal successful: account=$accountId, txn=$transactionId, amount=$amount, newBalance=$balance")
    replyTo ! TransactionSuccess(transactionId, balance)
  }

  private def appendAuditLog(entry: String): Unit = {
    val timestamped = s"${System.currentTimeMillis()} $entry"
    auditLog = auditLog :+ timestamped
    if (auditLog.size > maxAuditLogSize) {
      // In production, flush to persistent storage before trimming
      auditLog = auditLog.drop(auditLog.size - maxAuditLogSize)
    }
  }
}

object AccountActor {
  def props(accountId: String): Props = Props(new AccountActor(accountId))
}

// Example usage
object AccountSystem extends App {
  val system = ActorSystem("FinancialSystem")
  implicit val timeout: Timeout = Timeout(5.seconds)
  implicit val ec = system.dispatcher

  val account = system.actorOf(AccountActor.props("ACC-001"), "account-001")

  // All interactions go through message passing - thread-safe by design
  (account ? Deposit(BigDecimal("1000.00"), "TXN-001")).mapTo[AccountResponse].onComplete {
    case Success(TransactionSuccess(txnId, newBalance)) =>
      println(s"Deposit $txnId succeeded. New balance: $newBalance")
    case Success(TransactionFailure(txnId, reason)) =>
      println(s"Deposit $txnId failed: $reason")
    case Failure(ex) =>
      println(s"System error: ${ex.getMessage}")
  }

  (account ? Withdraw(BigDecimal("250.00"), "TXN-002")).mapTo[AccountResponse].onComplete {
    case Success(TransactionSuccess(txnId, newBalance)) =>
      println(s"Withdrawal $txnId succeeded. New balance: $newBalance")
    case Success(TransactionFailure(txnId, reason)) =>
      println(s"Withdrawal $txnId failed: $reason")
    case Failure(ex) =>
      println(s"System error: ${ex.getMessage}")
  }

  // Attempt overdraft
  (account ? Withdraw(BigDecimal("5000.00"), "TXN-003")).mapTo[AccountResponse].onComplete {
    case Success(response) => println(s"Overdraft attempt result: $response")
    case Failure(ex) => println(s"System error: ${ex.getMessage}")
  }

  system.scheduler.scheduleOnce(3.seconds) {
    system.terminate()
  }
}